+    /**
+     * Usable columns/rows for full-size windows (excludes reserved shelf area).
+     */
+    get effectiveCols() {
+        if (!this._reserved) return this.cols;
+        // Right shelf: reserved starts at rv.col
+        // Left shelf: reserved ends at rv.col + rv.spanCols
+        const rv = this._reserved;
+        if (rv.col === 0) return this.cols - rv.spanCols; // left shelf
+        return rv.col; // right shelf (and top/bottom don't reduce cols)
+    }
+
+    get effectiveRows() {
+        if (!this._reserved) return this.rows;
+        const rv = this._reserved;
+        if (rv.row === 0 && rv.spanCols === this.cols) return this.rows - rv.spanRows; // top shelf
+        if (rv.row > 0 && rv.spanCols === this.cols) return rv.row; // bottom shelf
+        return this.rows;
+    }
+
     get windowCount() { return this._windows.size; }
     getAllWindows() { return new Map(this._windows); }
